import { StyledDiv } from "./styles";
import ProjectCard from "./ProjectCard";

export default function Projects() {
  return (
    <StyledDiv>
      <ProjectCard
        url="https://github.com/var1ch/todo-app"
        icon="todo"
        projectTitle="Todo"
        techStack={["TypeScript", "React", "Redux", "MaterialUI"]}
      />
      <ProjectCard
        url="https://github.com/var1ch/quiz-app"
        icon="quiz"
        projectTitle="Quiz"
        techStack={["TypeScript", "React", "Redux", "MaterialUI"]}
      />
      <ProjectCard
        url="https://github.com/var1ch/markdownpreview-app"
        icon="md"
        projectTitle="Markdown Preview"
        techStack={["TypeScript", "React", "Redux", "MaterialUI"]}
      />
      <ProjectCard
        url="https://github.com/var1ch/inotasks"
        icon="android"
        projectTitle="Inotasks"
        techStack={["TypeScript", "ReactNative", "Redux", "ReactNavigation"]}
      />
    </StyledDiv>
  );
}
